import type { StateCreator } from 'zustand';
import {
  PointsProductsStatus,
  type PointsProductsState,
  type PointsProduct,
} from '../models';

export interface PointsProductsActions {
  setStatus: (status: PointsProductsStatus) => void;
  setProducts: (products: PointsProduct[]) => void;
  setConversionFactor: (factor: number) => void;
  setError: (error?: string) => void;
  reset: () => void;
}

export interface PointsProductsSlice {
  pointsProducts: PointsProductsState;
  pointsProductsActions: PointsProductsActions;
}

const INITIAL_POINTS_PRODUCTS_STATE: PointsProductsState = {
  products: [],
  conversionFactor: 0.1,
  status: PointsProductsStatus.IDLE,
  error: undefined,
};

export const createPointsProductsSlice: StateCreator<
  PointsProductsSlice,
  [],
  [],
  PointsProductsSlice
> = (set) => ({
  pointsProducts: INITIAL_POINTS_PRODUCTS_STATE,
  pointsProductsActions: {
    setStatus: (status) =>
      set((state) => ({
        pointsProducts: { ...state.pointsProducts, status },
      })),
    setProducts: (products) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          products,
          status: PointsProductsStatus.SUCCESS,
          error: undefined,
        },
      })),
    setConversionFactor: (conversionFactor) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          conversionFactor,
        },
      })),
    setError: (error) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          status: PointsProductsStatus.ERROR,
          error,
        },
      })),
    reset: () =>
      set({
        pointsProducts: INITIAL_POINTS_PRODUCTS_STATE,
      }),
  },
});

